// Build a location-aware search query
const chatInput = $('When chat message received').item.json.chatInput || '';
const ipData = $json || {};

// Build location string from IP geolocation
let locationStr = 'current location';
if (ipData.status === 'success' && ipData.city) {
  locationStr = `${ipData.city}, ${ipData.regionName || ''}, ${ipData.country || ''}`.trim();
}

// Check if user already specified a location in the query — avoid doubling up
const mentionsLocation = /\b(in|near|around|at|within)\s+[A-Z][a-zA-Z\s]{2,}/i.test(chatInput);

const searchQuery = mentionsLocation
  ? `${chatInput} phone number contact reservation`
  : `${chatInput} in ${locationStr} phone number contact reservation`;

return [{
  json: {
    searchQuery,
    locationStr,
    originalQuery: chatInput
  }
}];

// Validate Firecrawl response and consolidate content for LLM extraction
const res = $json;

if (res.error || !res.data || !Array.isArray(res.data)) {
  throw new Error(`Firecrawl failed: ${JSON.stringify(res.error || 'No data returned. Check your Firecrawl API key.')}`);
}

if (res.data.length === 0) {
  throw new Error(`No search results found for: "${$('Build Search Query').item.json.searchQuery}". Try a different query.`);
}

// Concatenate all returned content for the LLM to process
const combinedContent = res.data
  .map(r => `SOURCE: ${r.title || 'N/A'}\nURL: ${r.url || 'N/A'}\nCONTENT:\n${r.markdown || r.description || ''}\n---`)
  .join('\n\n');

return [{
  json: {
    combinedContent,
    resultCount: res.data.length,
    searchQuery: $('Build Search Query').item.json.searchQuery,
    locationStr: $('Build Search Query').item.json.locationStr,
    originalQuery: $('Build Search Query').item.json.originalQuery
  }
}];

// Parse OpenAI output, validate E.164 phone numbers, and deduplicate
const raw = $json?.choices?.[0]?.message?.content;

if (!raw) {
  const errDetail = $json?.error?.message || JSON.stringify($json);
  throw new Error(`OpenAI extraction failed: ${errDetail}`);
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error(`Failed to parse OpenAI JSON: ${raw.substring(0, 200)}`);
}

const restaurants = parsed.restaurants || [];

if (restaurants.length === 0) {
  throw new Error('OpenAI found no restaurants in the search results. Try a more specific query.');
}

const e164Regex = /^\+[1-9]\d{6,14}$/;
const seenPhones = new Set();
const valid = [];

for (const r of restaurants) {
  const phone = (r.phone || '').replace(/\s/g, '').trim();
  if (!e164Regex.test(phone)) {
    console.log(`Skipped invalid phone for ${r.name}: ${phone}`);
    continue;
  }
  if (seenPhones.has(phone)) {
    console.log(`Skipped duplicate phone: ${phone}`);
    continue;
  }
  seenPhones.add(phone);
  valid.push({
    name: (r.name || 'Unknown Restaurant').trim(),
    phone,
    address: (r.address || '').trim()
  });
}

if (valid.length === 0) {
  throw new Error(`No valid E.164 phone numbers found. Raw extraction: ${raw.substring(0, 300)}`);
}

const meta = {
  originalQuery: $('Build Search Query').item.json.originalQuery,
  locationStr: $('Build Search Query').item.json.locationStr
};

return valid.map(r => ({ json: { ...r, ...meta } }));

// Normalise the ElevenLabs response — handles both success and API errors gracefully
const callResponse = $json;
const restaurantData = $('Throttle Between Calls').item.json;

const callId =
  callResponse.call_id ||
  callResponse.id ||
  callResponse.callSid ||
  callResponse.conversation_id ||
  null;

const hasError =
  callResponse.detail !== undefined ||
  callResponse.error !== undefined ||
  (callResponse.status >= 400);

const isSuccess = !hasError && callId !== null;

let errorMsg = null;
if (!isSuccess) {
  errorMsg =
    callResponse.detail ||
    callResponse.error?.message ||
    JSON.stringify(callResponse).substring(0, 200);
}

return [{
  json: {
    restaurantName: restaurantData.name || 'Unknown',
    phone: restaurantData.phone || 'Unknown',
    address: restaurantData.address || '',
    callId: callId || 'N/A',
    status: isSuccess ? 'initiated' : 'failed',
    error: errorMsg,
    timestamp: new Date().toISOString(),
    locationStr: restaurantData.locationStr || '',
    originalQuery: restaurantData.originalQuery || ''
  }
}];

// Build the final human-readable chat response
const calls = $json.calls || [];

if (!calls.length) {
  return [{ json: { output: 'No calls were made. No restaurants with valid phone numbers were found.' } }];
}

const initiated = calls.filter(c => c.status === 'initiated');
const failed = calls.filter(c => c.status === 'failed');
const location = calls[0]?.locationStr || 'your location';
const query = calls[0]?.originalQuery || '';

const lines = [
  `Search: "${query}" near ${location}`,
  `Found ${calls.length} restaurant(s). Calls initiated: ${initiated.length}. Failed: ${failed.length}.`,
  ''
];

if (initiated.length > 0) {
  lines.push('Calls initiated:');
  initiated.forEach(c => {
    const addr = c.address ? ` — ${c.address}` : '';
    lines.push(`  ${c.restaurantName}${addr}`);
    lines.push(`    Phone: ${c.phone} | Call ID: ${c.callId}`);
  });
}

if (failed.length > 0) {
  lines.push('');
  lines.push('Failed:');
  failed.forEach(c => {
    lines.push(`  ${c.restaurantName} (${c.phone}): ${c.error || 'Unknown error'}`);
  });
}

lines.push('');
lines.push('All results logged to Google Sheets.');

return [{ json: { output: lines.join('\n') } }];
